original_content=$(cat ledger-api/main.go)

# Define the function to be replaced
old_function="func readBalance(db *sql.DB, account string) (int64, error) {
	var balance int64
	err := db.QueryRow(\"SELECT balance_cents FROM accounts WHERE id = $1\", account).Scan(&balance)
	return balance, err
}"

# Define the new function
new_function="func readBalance(db *sql.DB, account string) (int64, error) {
	tx, err := db.Begin(&sql.TxOptions{ReadOnly: true, Deferrable: true})
	if err != nil {
		return 0, err
	}
	defer tx.Rollback() // Defer rollback in case of error.

	var balance int64
	err = tx.QueryRow(\"SELECT balance_cents FROM accounts WHERE id = $1\", account).Scan(&balance)
	if err != nil {
		return 0, err
	}

	// Commit the read-only transaction.
	if err := tx.Commit(); err != nil {
		return 0, err
	}

	return balance, nil
}"

# Use sed to replace the function in the content
# Note: Using a temporary delimiter to handle special characters in the replacement strings.
new_content=$(echo "$original_content" | sed -e "s|$(echo "$old_function" | sed -e 's/[]\/$*.^[]/\\&/g')|$(echo "$new_function" | sed -e 's/[]\/$*.^[]/\\&/g')|g")

# Write the modified content back to the file
echo "$new_content" > ledger-api/main.go

